<?php
declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';exigirPermiso('notifications.view');$pdo=obtenerConexion();$uid=(int)$_SESSION['usuario_id'];$estado=(string)($_GET['estado']??'');$categoria=trim((string)($_GET['categoria']??''));$pagina=max(1,(int)($_GET['pagina']??1));$limite=25;$where=' WHERE user_id=:u';$pa=['u'=>$uid];if(in_array($estado,['pendiente','visto'],true)){$where.=' AND status=:estado';$pa['estado']=$estado;}if($categoria!==''){$where.=' AND category=:cat';$pa['cat']=mb_substr($categoria,0,50);}$q=$pdo->prepare('SELECT COUNT(*) FROM admin_notices'.$where);$q->execute($pa);$total=(int)$q->fetchColumn();$q=$pdo->prepare('SELECT * FROM admin_notices'.$where.' ORDER BY created_at DESC,id DESC LIMIT :lim OFFSET :off');foreach($pa as$k=>$v)$q->bindValue(':'.$k,$v);$q->bindValue(':lim',$limite,PDO::PARAM_INT);$q->bindValue(':off',($pagina-1)*$limite,PDO::PARAM_INT);$q->execute();$filas=$q->fetchAll();$categorias=$pdo->prepare('SELECT DISTINCT category FROM admin_notices WHERE user_id=:u ORDER BY category');$categorias->execute(['u'=>$uid]);cmsCabecera('Notificaciones','notificaciones/index.php','Historial paginado de actividad operativa relevante.');?>
<div class="card card-rounded"><div class="card-body"><form class="row g-2 mb-3"><div class="col-md-4"><select class="form-select" name="estado"><option value="">Todas</option><option value="pendiente" <?=$estado==='pendiente'?'selected':''?>>No leídas</option><option value="visto" <?=$estado==='visto'?'selected':''?>>Leídas</option></select></div><div class="col-md-4"><select class="form-select" name="categoria"><option value="">Todas las categorías</option><?php foreach($categorias->fetchAll(PDO::FETCH_COLUMN) as$c):?><option <?=$categoria===$c?'selected':''?>><?=atenea_e($c)?></option><?php endforeach;?></select></div><div class="col-md-2"><button class="btn btn-outline-primary w-100">Filtrar</button></div></form><form method="post" action="accion.php" class="mb-3"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="accion" value="todas"><button class="btn btn-sm btn-light">Marcar todas como leídas</button></form><?php foreach($filas as$n):?><div class="border-bottom py-3 d-flex justify-content-between"><div><span class="badge bg-<?=$n['level']==='error'?'danger':($n['level']==='advertencia'?'warning':'primary')?>"><?=atenea_e($n['category'])?></span><h2 class="h6 mt-2 mb-1"><?=atenea_e($n['title'])?></h2><p class="mb-1"><?=atenea_e($n['message'])?></p><small class="text-muted"><?=date('d/m/Y H:i',strtotime($n['created_at']))?></small><?php if($n['action_url']):?> · <a href="<?=atenea_e($n['action_url'])?>">Abrir registro</a><?php endif;?></div><?php if($n['status']==='pendiente'):?><form method="post" action="accion.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="accion" value="leer"><input type="hidden" name="id" value="<?=$n['id']?>"><button class="btn btn-sm btn-outline-primary">Marcar leída</button></form><?php endif;?></div><?php endforeach;?><?php if(!$filas):?><div class="text-center py-5 text-muted">No hay notificaciones para estos filtros.</div><?php endif;?><?=cmsPaginacionSimple($pagina,(int)ceil($total/$limite),$_GET)??''?></div></div><?php cmsPie();
